var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"언니, 이쪽이야. 빨리 와.","JPN":"お姉ちゃん、こっちだよ。早く来て。","ENG":"Sobin, this way. Hurry.","TWN":"姐姐，這邊，快來。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"소리야, 진짜 여기 재밌는 게 있어?","JPN":"コナツちゃん、面白いことって何？本当にこんなところで見たの？","ENG":"Sori, are you sure there's something fun here?","TWN":"昭璃，這裡真的有好玩的嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"아까부터 사람이 안 보이는데...... 어른들도 없고......","JPN":"さっきから誰も見かけないし……大人たちもいないけど……","ENG":"I haven't seen anybody for a while... And there are no adults here...","TWN":"從剛才開始就一個人都看不到……也沒有大人……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"왜 그래, 언니. 오늘은 나랑 놀아 주기로 했잖아.","JPN":"どうしたのよ、お姉ちゃん。今日はアタシと遊ぶ約束だったじゃない。","ENG":"What's wrong, Sobin? You promised to play with me today.","TWN":"怎麼了，姐姐。妳不是說好，今天要陪我玩的嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"혹시 겁나서 그래?","JPN":"もしかして怖くなっちゃった？","ENG":"Are you scared?","TWN":"該不會是害怕了吧？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"나, 난 겁 안 나! 언니인걸!","JPN":"こ、怖くなんかないもん！お姉ちゃんだもん！","ENG":"I-I'm not scared! I'm your older sister!","TWN":"我、我才不怕！我可是姐姐！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"오, 약속한 시간에 딱 맞춰 왔구나.","JPN":"おお、約束の時間ぴったりに来てくれたね。","ENG":"Oh, you're right on time.","TWN":"哦，妳來得很準時呢。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"아저씨!","JPN":"おじさん！","ENG":"Mister!","TWN":"叔叔！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"소리야! 가면 안 돼!","JPN":"コナツちゃん！行っちゃダメ！","ENG":"Sori! Don't go!","TWN":"昭璃！不要過去！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"선생님이 모르는 사람 따라가면 안 된다고 했잖아!","JPN":"知らない人について行っちゃダメだって、先生が言ってたじゃない！","ENG":"The teacher said not to follow strangers!","TWN":"老師不是說不能跟陌生人走嗎！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"괜찮아, 착한 아저씨거든! 언니가 이제부터 그 못난이들이랑 안 놀게 해 준댔어!","JPN":"平気よ、おじさんは優しいもん！もうお姉ちゃんがあのぶさいくたちと遊ばないようにしてくれるって言ってたの！","ENG":"It's okay, he's really nice! He's going to help you get rid of those losers!","TWN":"不要緊，這個叔叔是好人！他說可以讓姐姐再也不用跟那些笨蛋們一起玩！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"걔네들은 못난이가 아니라 내 친구야!","JPN":"ぶさいくじゃないよ。私の友達だもん！","ENG":"They're not losers, they're my friends!","TWN":"他們不是笨蛋！他們是我的朋友！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"아, 아저씨가 소빈이한테 이상한 얘기 한 거죠? 경찰 부를 거야!","JPN":"お、おじさんがコナツちゃんに変なことを言ったんですね？ケーサツを呼びますよ！","ENG":"D-did you say something weird to Sori? I'm calling the cops!","TWN":"叔、叔叔對昭璃說了奇怪的話吧？我要叫警察了！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"하하. 이상한 얘기라니. 아저씨는 그냥 좀 도와 준다고 했단다.","JPN":"ハハッ、変なこととは心外だな。おじさんは親切心で力を貸すと言ったんだ。","ENG":"Hah hah. What do you mean, something weird? I just told her that I'm going to help her.","TWN":"哈哈！居然說是奇怪的話。叔叔只是幫她一個小忙而已。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"그래. 그런 애들이랑 놀고 있으면 안 되지.","JPN":"お嬢ちゃんの言うとおりさ。あんな子たちと遊んでちゃいけないんだぞ。","ENG":"Yes. You really shouldn't be playing with those kids.","TWN":"是啊，妳不能跟那樣的小孩玩。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"......!","JPN":"……！","ENG":"......!","TWN":"……！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"아, 아저씨? 이 사람들은 누구야? 아저씨 부하들?","JPN":"お、おじさん？この人たちは誰？おじさんの会社の人たちなの？","ENG":"M-Mister? Who are these people? Are they your employees?","TWN":"叔、叔叔？這些人是誰啊？叔叔的手下嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"자, 공주님은 볼일 끝났으니 가봐도 된다.","JPN":"さあ、もう用は済んだからね。お嬢ちゃんはもうお家に帰る時間だよ。","ENG":"Okay, Princess. You're finished here. Go on.","TWN":"好了，小公主該做的事已經做完了，妳現在可以回去了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"물론 아저씨랑 봤다고 남들한테 말하지는 말고.","JPN":"わかってるだろうけど、おじさんに会ったことは誰にも言っちゃダメだからね。","ENG":"And of course, you can't tell anyone about us.","TWN":"當然，見到叔叔的事情不可以跟別人說喔。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"저 계집애가 의뢰 받은 실험체다. 잡아.","JPN":"あの小娘が依頼の実験体だ。捕らえろ。","ENG":"That girl is the requested experiment subject. Get her.","TWN":"那小妞就是委託裡提的實驗體，抓住她。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"예!","JPN":"はっ！","ENG":"Yes, sir!","TWN":"是！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"소리야! 어서 도망가!","JPN":"コナツちゃん！早く逃げて！","ENG":"Sori! Run!","TWN":"昭璃！快逃！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"꺄아악!","JPN":"きゃああっ！","ENG":"Ahhhh!","TWN":"呀啊啊！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_GUN_FIRE_SMALL_04"},{"id":"L41_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"어, 언니!!","JPN":"お、お姉ちゃん！！","ENG":"S-Sobin!","TWN":"姐姐！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"언니한테 무슨 짓이야! 빨리 그만하라고 해!! 그만해!!","JPN":"お姉ちゃんに何するのよ！早くやめさせて！！やめてったら！！","ENG":"What are you doing to my sister?! Tell them to stop! Stop!","TWN":"你們要對姐姐做什麼！快住手！住手！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"소...... 소리야......","JPN":"コ……コナツちゃん……","ENG":"So... Sori...","TWN":"昭……璃……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"윽...... 흑...... 아파...... 윽......","JPN":"うっ……あぅ……痛い……うぅ……","ENG":"Ugh... *Sob* It hurts... Ugh...","TWN":"嗚……嗚嗚……好痛……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"얘야. 골목대장이라고 총 든 아저씨들한테 반항하면 큰일나요.","JPN":"こいつ。銃を持った大人に立ち向かうのは感心しないな。痛い目に遭っても知らないよ？","ENG":"Kid. Just because you're a queen amongst kids, you can't go against people with guns.","TWN":"孩子，仗著自己是社區小霸王就反抗拿著槍的叔叔們，可是會出大事的喔。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"이렇게 말이야.","JPN":"ほら、こんなふうに。","ENG":"As you see right here.","TWN":"就像這樣。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"어, 언니...... 언니......","JPN":"お、お姉ちゃん……おねえちゃ…ん……","ENG":"S-Sobin... Sobin...","TWN":"嗚，姐姐……姐姐……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"아으...... 흑...... 소리, 야...... 도망......","JPN":"あう……うぅっ…コナ、ツ……逃げ……","ENG":"Ahh... *Sob* Sori... Run...","TWN":"啊……嗚……昭璃，快……逃……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"걱정 마렴. 네 동생 잘못 건드리다간 클라이언트가 날 닭모이로 만들지도 모르거든.","JPN":"心配要らないさ。もし君の妹さんを傷つけてしまったら、僕は鳥の餌になってしまうんだから。怖いクライアント様がいるんでね。","ENG":"Rest assured. If something happens to your sister, our client is going to feed us to the chickens.","TWN":"別擔心。如果對妳妹妹出手的話，客戶說不定會把我們做成雞飼料呢。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"그리고 쟤가 여기까지 널 안 불러냈으면 벌건 백주대낮에 어떻게 애를 데려가겠니.","JPN":"それに何より、君をこんなところに呼び出したのはこの子だろ？妹さんの協力があってこそ、白昼堂々と人攫いができるんだ。","ENG":"And if she didn't lure you in here, we wouldn't have the chance to kidnap you in the middle of the day.","TWN":"而且要不是她把妳叫到這裡，我們怎麼敢在光天化日之下綁架小朋友呢？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"그렇지, 공주님?","JPN":"そうだろ？お嬢ちゃん。","ENG":"Aren't I right, Princess?","TWN":"是吧，小公主？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"힉......","JPN":"ひッ……！","ENG":"Hic...","TWN":"咿……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"워치 압수하고 마취제 투여해. 30분 뒤면 배가 출발한다.","JPN":"ウォッチを取り上げて麻酔を打て。あと30分もすれば出港だ。","ENG":"Take her Watch and anesthetize her. The ship will leave in 30 minutes.","TWN":"沒收能量環後注射麻醉，30分鐘後開船。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"자, 공주님. 아저씨가 하나만 알려 줄게.","JPN":"さて、お嬢ちゃん。おじさんが一つ教訓を教えてあげよう。","ENG":"Now, Princess. Let me just tell you one thing.","TWN":"那麼，小公主，大叔就告訴妳一件事吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"어, 언니...... 언니를 놔 주세요......","JPN":"お、お姉ちゃん……お姉ちゃんを…放して……","ENG":"S-Sobin... Please let Sobin go...","TWN":"姐、姐姐……拜託妳放開姐姐……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"잘못했어요...... 제가 잘못했어요...... 앞으로 애들한테 나쁜 말 안 할게요.","JPN":"ゴメンナサイ……もうしません……二度とみんなのこと悪く言いませんから。","ENG":"I'm sorry... It's all my fault... I won't be mean to the other kids any more.","TWN":"對不起……是我錯了……我以後再也不說其他小朋友的壞話了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"장난감 자랑하지도 않을게요. 그러니까 언니는......","JPN":"オモチャの自慢もしません。だからお姉ちゃんは……","ENG":"I won't brag about my toys. So please, let Sobin...","TWN":"再也不會炫耀玩具了，所以請把姐姐……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"아니지.","JPN":"いやいや、そうじゃないだろ？","ENG":"No.","TWN":"不行喔。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"여기서 풀어 주면 네 언니는 자기가 무슨 짓을 당했는지 다 얘기할 텐데?","JPN":"ここでお姉ちゃんを解放したとしよう。するとお姉ちゃんは、どんな目に遭ったかみんなに話すだろうね。","ENG":"If I let her go here, she's going to tell the world what happened to her today.","TWN":"要是在這裡放了妳的姐姐，她就會把妳做了什麼全都說出去喔。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"그럼 넌 어떻게 되겠니?","JPN":"そしたら、君はどうなると思う？","ENG":"And then what will happen to you?","TWN":"那妳會怎麼樣呢？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"소리......야...... 그 아저씨 말...... 들으면 안 돼......","JPN":"コナツ……ちゃん……あんなやつの話……聞いちゃ、ダメ……","ENG":"Sori... Sori... Don't listen... to that man...","TWN":"昭璃……別聽……他說的話……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"엄마한테 엄청 혼나겠지? 안 그러니?","JPN":"ママにこっぴどく怒られるだろうね。違うかい？","ENG":"Your mom is going to get real angry. Don't you think so?","TWN":"妳會被媽媽臭罵一頓吧？不是嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"그래, 입 꾹 닫고 있으면 아무도 모를 거야.","JPN":"そう……口をつぐんでさえいれば、誰にも知られることはないんだ。","ENG":"Yes, just keep your mouth shut tightly and no one will know.","TWN":"沒錯！只要妳緊緊閉著嘴巴，那就誰都不會知道。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"소리...... 야......","JPN":"コナツ……ちゃん……","ENG":"Sori... ...","TWN":"昭……璃……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"축하해, 공주님. 넌 오늘부터 후계자란다. 원하는 건 뭐든 손에 넣을 수 있어.","JPN":"おめでとう、お嬢ちゃん。今日この瞬間から君は相続人だ。欲しいものは何でも手に入るだろう。","ENG":"Congratulations, Princess. You're the rightful heir now. You can get anything you want from now on.","TWN":"恭喜妳啊，小公主。妳從今天之後就是繼承人，可以得到任何妳想要的東西了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"아, 그리고 가기 전에 아저씨가 충고 하나만 해 주마.","JPN":"ただし、おじさんは親切だからね。別れる前に一つだけ忠告しておくよ。","ENG":"Oh, and let me give you a bit of advice before I go.","TWN":"啊，走之前，叔叔給妳個忠告吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"엄마 말 잘 들으렴.","JPN":"ママの言うことはよく聞くように。","ENG":"Listen to your mother.","TWN":"要好好聽媽媽的話喔。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"......친자식이라고 안 이러란 법 없잖니.","JPN":"……実の子供だからって、同じ目に遭わせないとは限らないからね。","ENG":"You never know what she might do, even if you're her child.","TWN":" …即使你是親生的，也不保證不會變成這樣喔？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};